text:
{
  "formal_minutes": {
    "meeting_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "item": "공개 릴리스 목표 시각은 스모크 테스트 통과를 전제로 금요일 15:00 KST로 둔다.",
        "basis": "Seoyeon의 수요일 제안 이후, Doyun이 스모크 테스트 선통과 필요를 제기했고 최종 결정이 명시되었다."
      },
      {
        "item": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토로 넘어간다.",
        "basis": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하자는 제안은 반려되었고, 대체 판단 기준이 최종 결정으로 정리되었다."
      }
    ],
    "rejected_proposals": [
      {
        "item": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경하자.",
        "proposed_by": "Hara",
        "result": "반려"
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 릴리스",
        "status": "내부 스트레치 목표",
        "note": "공개 릴리스 확정 일정이 아니며, 스모크 테스트 선통과 조건보다 우선하지 않는다."
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차는 가능하면 목요일까지 검토해야 한다는 의견이 있었으나, 담당자는 지정되지 않았다."
      },
      {
        "item": "Hara는 Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 확인하기로 했으나, 정확한 기한은 정해지지 않았다."
      }
    ],
    "risks": [
      {
        "item": "tarball 경로가 잘못되면 릴리스가 지연될 수 있다."
      },
      {
        "item": "README 설치 절차가 오래되었거나 부정확하면 릴리스 노트가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "item": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "명시적으로 확인됨"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "명시적으로 확인됨"
    },
    {
      "owner": "미정",
      "task": "README 설치 절차를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능 시점",
      "status": "미배정",
      "source_certainty": "의견 수준으로 언급됨"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 공유한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "확정",
      "source_certainty": "행동 자체는 확인됨, 기한은 미확정"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun의 스모크 테스트 재실행 결과가 금요일 10:00 KST까지 공유되었는지 확인한다.",
      "스모크 실패 시 Doyun의 트리아지 노트가 금요일 12:00 KST까지 action_items.md에 반영되었는지 확인한다.",
      "packageName mismatch가 발생하면 스크립트 완화가 아니라 패키지 설정과 계약 정의를 먼저 점검한다.",
      "Minjun 결과 게시 후 Hara의 tarball 경로 확인 결과를 수집한다.",
      "README 설치 절차 검토 담당자 지정 여부와 실제 검토 완료 여부를 확인한다.",
      "최종 릴리스 승인 권한자와 릴리스 노트의 수요일 스트레치 목표 언급 여부를 후속 의제로 정리한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "미지정 담당자",
      "명시되지 않은 기한"
    ]
  },
  "non_invention_rules": [
    "인라인 픽스처에 없는 고객, 외부 파트너, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "담당자와 기한은 명시된 경우에만 기록하고, 없으면 미정으로 둔다.",
    "수요일 릴리스는 확정 일정이 아니라 내부 스트레치 목표로만 기록한다.",
    "반려된 제안은 확정 결정과 분리해 기록한다.",
    "오픈 질문은 답을 추정하지 않고 미해결 상태로 유지한다."
  ]
}
